class Account {
protected:
    int accountNumber;
    std::string ownerName;
    double balance;

public:
    Account(int accNum, const std::string& name, double bal) 
        : accountNumber(accNum), ownerName(name), balance(bal) {}

    virtual ~Account() = default;

    virtual double calculateInterest() const = 0;

    virtual void deposit(double amount) {
        if (amount <= 0) {
            throw std::invalid_argument("Deposit amount must be positive");
        }
        balance += amount;
        Logger::log("Deposited $" + std::to_string(amount) + " to account " + std::to_string(accountNumber));
    }

    virtual void withdraw(double amount) {
        if (amount <= 0) {
            throw std::invalid_argument("Withdrawal amount must be positive");
        }
        if (amount > balance) {
            throw std::runtime_error("Insufficient funds for withdrawal");
        }
        balance -= amount;
        Logger::log("Withdrew $" + std::to_string(amount) + " from account " + std::to_string(accountNumber));
    }

    double getBalance() const { return balance; }
    int getAccountNumber() const { return accountNumber; }
    const std::string& getOwnerName() const { return ownerName; }

    virtual void displayInfo() const {
        std::cout << "Account #" << accountNumber << " - " << ownerName 
                  << " - Balance: $" << std::fixed << std::setprecision(2) << balance;
