                std::cout << "Interest: $" << std::fixed << std::setprecision(2) 
                          << (*it)->calculateInterest() << std::endl;
                std::cout << "------------------------" << std::endl;
            }
        }
    }

    size_t getAccountCount() const {
        return accountStack.size();
    }
