	return &ChatServer{
		messages:     make(chan Message, capacity),
		userSessions: make(map[string]bool),
	}
}

func (cs *ChatServer) AddUser(username string) bool {
	cs.mutex.Lock()
	defer cs.mutex.Unlock()

	if _, exists := cs.userSessions[username]; exists {
		return false
	}
	cs.userSessions[username] = true
	return true
}

func (cs *ChatServer) RemoveUser(username string) bool {
	cs.mutex.Lock()
	defer cs.mutex.Unlock()

	if _, exists := cs.userSessions[username]; !exists {
		return false
	}
	delete(cs.userSessions, username)
	return true
}

func (cs *ChatServer) PostMessage(username, content string) bool {
	msg := Message{
		User:    username,
		Content: content,
		Time:    time.Now(),
	}

	// Try to add message to channel without blocking
	select {
	case cs.messages <- msg:
		return true
	default:
		// Channel is full, remove oldest message and add new one
		<-cs.messages
		cs.messages <- msg
		return true
	}
}

