package main

import (
	"errors"
	"fmt"
	"strings"
)

const (
	MaxRecords = 2000
)

type StudentGrade struct {
	Name  string
	Grade float64
}

type GradeManager struct {
	records []StudentGrade
}

func NewGradeManager() *GradeManager {
	return &GradeManager{
		records: make([]StudentGrade, 0, MaxRecords),
	}
}

func (gm *GradeManager) AddGrade(name string, grade float64) error {
	if len(gm.records) >= MaxRecords {
		return errors.New("maximum number of records reached")
	}

	name = strings.TrimSpace(name)
	if name == "" {
		return errors.New("student name cannot be empty")
	}

	// Check for duplicates
	for _, record := range gm.records {
		if strings.EqualFold(record.Name, name) {
			return errors.New("student already exists")
		}
	}

	gm.records = append(gm.records, StudentGrade{Name: name, Grade: grade})
	return nil
}

func (gm *GradeManager) UpdateGrade(name string, newGrade float64) error {
	name = strings.TrimSpace(name)
	if name == "" {
		return errors.New("student name cannot be empty")
	}

	for i, record := range gm.records {
		if strings.EqualFold(record.Name, name) {
			gm.records[i].Grade = newGrade
			return nil
		}
	}
	return errors.New("student not found")
}

func (gm *GradeManager) ListAllGrades() []StudentGrade {
	return gm.records
}

func main() {
	manager := NewGradeManager()

	// Add some sample grades
	_ = manager.AddGrade("Alice", 95.5)
	_ = manager.AddGrade("Bob", 87.0)
	_ = manager.AddGrade("Charlie", 76.5)

	// Update a grade
	_ = manager.UpdateGrade("Bob", 92.0)

	// List all grades
	fmt.Println("Student Grades:")
	for _, record := range manager.ListAllGrades() {
		fmt.Printf("%s: %.1f\n", record.Name, record.Grade)
	}
}
