use std::collections::HashSet;

fn rob(nums: &[i32]) -> i32 {
    if nums.is_empty() {
        return 0;
    }
    if nums.len() == 1 {
        return nums[0];
    }

    let mut memo = HashSet::new();
    let mut dp = vec![0; nums.len()];

    dp[0] = nums[0];
    dp[1] = nums[0].max(nums[1]);
    memo.insert(dp[0]);
    memo.insert(dp[1]);

    for i in 2..nums.len() {
        // Take the maximum of including the current element + dp[i-2]
        // or excluding the current element (dp[i-1])
        dp[i] = nums[i] + dp[i-2];
        dp[i] = dp[i].max(dp[i-1]);

        // Add to HashSet while ensuring it doesn't exceed 1500 elements
        memo.insert(dp[i]);
        if memo.len() > 1500 {
            // Remove the smallest element if we exceed the limit
            if let Some(&min) = memo.iter().min() {
                memo.remove(&min);
            }
        }
    }

    dp[nums.len() - 1]
}

fn main() {
    let nums = vec![2, 7, 9, 3, 1];
    println!("Maximum sum: {}", rob(&nums));

    let nums2 = vec![1, 2, 3, 1];
    println!("Maximum sum: {}", rob(&nums2));
}
