        : flightNumber(flightNum), origin(orig), destination(dest),
          departureTime(depTime), arrivalTime(arrTime), 
          totalSeats(seats), availableSeats(seats) {}

    std::string getFlightNumber() const { return flightNumber; }
    std::string getOrigin() const { return origin; }
    std::string getDestination() const { return destination; }
    std::string getDepartureTime() const { return departureTime; }
    std::string getArrivalTime() const { return arrivalTime; }
    int getTotalSeats() const { return totalSeats; }
    int getAvailableSeats() const { return availableSeats; }

