            reservationIds.push_back(reservationId);
            availableSeats--;
            return true;
        }
        return false;
    }

    bool cancelReservation(int reservationId) {
        auto it = std::find(reservationIds.begin(), reservationIds.end(), reservationId);
        if (it != reservationIds.end()) {
            reservationIds.erase(it);
            availableSeats++;
            return true;
        }
        return false;
