fn task_manager_cli() {
    let mut tasks: VecDeque<Task> = VecDeque::with_capacity(50);

    loop {
        print_menu();
        let choice = get_user_choice();

        match choice {
            1 => add_task(&mut tasks),
            2 => remove_task(&mut tasks),
            3 => view_tasks(&tasks),
            4 => mark_task_completed(&mut tasks),
            5 => break,
            _ => println!("Invalid choice, please try again."),
        }
    }
