fn print_menu() {
    println!("\n--- Task Manager ---");
    println!("1. Add task");
    println!("2. Remove task");
    println!("3. View tasks");
    println!("4. Mark task as completed");
    println!("5. Exit");
    print!("Enter your choice: ");
    io::stdout().flush().unwrap();
}

fn get_user_choice() -> usize {
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    input.trim().parse().unwrap_or(0)
}

fn add_task(tasks: &mut VecDeque<Task>) {
    if tasks.len() >= 50 {
        println!("Task list is full. Remove some tasks first.");
        return;
    }

    print!("Enter task description: ");
    io::stdout().flush().unwrap();

    let mut description = String::new();
    io::stdin().read_line(&mut description).unwrap();

    tasks.push_back(Task {
        description: description.trim().to_string(),
        completed: false,
    });

    println!("Task added successfully!");
}

fn remove_task(tasks: &mut VecDeque<Task>) {
    if tasks.is_empty() {
        println!("No tasks to remove.");
        return;
    }

    view_tasks(tasks);
    print!("Enter task number to remove: ");
    io::stdout().flush().unwrap();

    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();

    if let Ok(index) = input.trim().parse::<usize>() {
        if index > 0 && index <= tasks.len() {
            tasks.remove(index - 1);
            println!("Task removed successfully!");
        } else {
            println!("Invalid task number.");
        }
    } else {
        println!("Invalid input.");
    }
}

fn view_tasks(tasks: &VecDeque<Task>) {
    if tasks.is_empty() {
        println!("No tasks available.");
        return;
    }

    println!("\n--- Task List ---");
    for (i, task) in tasks.iter().enumerate() {
        println!("{}. {} [{}]", 
            i + 1, 
            task.description, 
            if task.completed { "X" } else { " " }
        );
    }
}

fn mark_task_completed(tasks: &mut VecDeque<Task>) {
    if tasks.is_empty() {
        println!("No tasks available.");
        return;
    }

    view_tasks(tasks);
    print!("Enter task number to mark as completed: ");
    io::stdout().flush().unwrap();

    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();

    if let Ok(index) = input.trim().parse::<usize>() {
        if index > 0 && index <= tasks.len() {
            if let Some(task) = tasks.get_mut(index - 1) {
                task.completed = true;
                println!("Task marked as completed!");
            }
        } else {
            println!("Invalid task number.");
        }
    } else {
        println!("Invalid input.");
    }
}
