using namespace std;

// Structure to represent an intersection in the grid
struct Intersection {
    int id;
    int x, y;

    // Constructor
    Intersection(int id, int x, int y) : id(id), x(x), y(y) {}
};

// Hash function for pair<int, int> to use in unordered_set
struct PairHash {
    size_t operator()(const pair<int, int>& p) const {
        return hash<int>()(p.first) ^ hash<int>()(p.second);
    }
};

class UrbanGrid {
private:
    int gridSize;
    vector<vector<int>> travelTime; // Time to travel between adjacent intersections
    vector<Intersection> intersections;

public:
    // Constructor
    UrbanGrid(int size) : gridSize(size) {
        // Initialize travel time between intersections (adjacency matrix)
        travelTime.resize(size * size, vector<int>(size * size, -1));

        // Create intersections
        for (int i = 0; i < size; i++) {
            for (int j = 0; j < size; j++) {
                int id = i * size + j;
                intersections.push_back(Intersection(id, i, j));
            }
        }

        // Connect adjacent intersections with random travel times
        srand(time(nullptr));
        for (int i = 0; i < size; i++) {
            for (int j = 0; j < size; j++) {
                int currentId = i * size + j;

                // Connect to right neighbor
                if (j < size - 1) {
                    int rightId = i * size + (j + 1);
                    int time = 1 + rand() % 10; // Random travel time between 1 and 10
                    travelTime[currentId][rightId] = time;
                    travelTime[rightId][currentId] = time;
                }

                // Connect to bottom neighbor
                if (i < size - 1) {
                    int bottomId = (i + 1) * size + j;
                    int time = 1 + rand() % 10; // Random travel time between 1 and 10
                    travelTime[currentId][bottomId] = time;
                    travelTime[bottomId][currentId] = time;
                }
            }
        }
    }

    // Get neighboring intersections for a given intersection
    vector<int> getNeighbors(int id) {
        vector<int> neighbors;
        for (int i = 0; i < gridSize * gridSize; i++) {
            if (travelTime[id][i] != -1) {
                neighbors.push_back(i);
            }
        }
        return neighbors;
    }

    // Find shortest path using dynamic programming with Dijkstra's algorithm
    vector<int> findShortestPath(int startId, int endId) {
        vector<int> distance(gridSize * gridSize, numeric_limits<int>::max());
        vector<int> previous(gridSize * gridSize, -1);

        // Priority queue for Dijkstra's algorithm
        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

        // Set of visited intersections to prevent cycles
        unordered_set<int> visited;

        // Start with the source intersection
        distance[startId] = 0;
        pq.push({0, startId});

        while (!pq.empty()) {
            int currentId = pq.top().second;
            int currentDist = pq.top().first;
            pq.pop();

            // If we've reached the destination, we're done
            if (currentId == endId) {
                break;
            }

            // Skip if we've already processed this intersection
            if (visited.find(currentId) != visited.end()) {
                continue;
            }

            // Mark as visited
            visited.insert(currentId);

            // Check all neighboring intersections
            for (int neighborId : getNeighbors(currentId)) {
                // Skip if already visited
                if (visited.find(neighborId) != visited.end()) {
                    continue;
                }

                int newDist = currentDist + travelTime[currentId][neighborId];

                // If we found a shorter path, update distance and previous
                if (newDist < distance[neighborId]) {
                    distance[neighborId] = newDist;
                    previous[neighborId] = currentId;
                    pq.push({newDist, neighborId});
                }
            }
        }

        // Reconstruct the path
        vector<int> path;
        for (int at = endId; at != -1; at = previous[at]) {
            path.push_back(at);
        }
        reverse(path.begin(), path.end());

        // Check if a path was found
        if (path.size() <= 1 || path[0] != startId) {
            return {}; // No path found
        }

        return path;
    }

    // Print the grid and the path
    void printGridWithPath(const vector<int>& path) {
        // Create a set of path intersections for easy lookup
        unordered_set<int> pathSet(path.begin(), path.end());

        for (int i = 0; i < gridSize; i++) {
            for (int j = 0; j < gridSize; j++) {
                int id = i * gridSize + j;
                if (pathSet.find(id) != pathSet.end()) {
                    cout << "* ";
                } else {
                    cout << ". ";
                }
            }
            cout << endl;
        }
    }

    // Get the total travel time for a path
    int getTotalTravelTime(const vector<int>& path) {
        int totalTime = 0;
        for (size_t i = 0; i < path.size() - 1; i++) {
            totalTime += travelTime[path[i]][path[i + 1]];
        }
        return totalTime;
    }
};

int main() {
    // Create a grid (size can be adjusted up to 1000)
    int gridSize = 10; // For demonstration, using a smaller grid
    UrbanGrid grid(gridSize);

    // Define start and end points
    int startX = 0, startY = 0;
    int endX = gridSize - 1, endY = gridSize - 1;

    int startId = startX * gridSize + startY;
    int endId = endX * gridSize + endY;

    // Find the shortest path
    vector<int> path = grid.findShortestPath(startId, endId);

    // Print results
    if (path.empty()) {
        cout << "No path found!" << endl;
    } else {
        cout << "Shortest path from (" << startX << "," << startY << ") to (" 
             << endX << "," << endY << "):" << endl;

        cout << "Path: ";
        for (size_t i = 0; i < path.size(); i++) {
            int x = path[i] / gridSize;
            int y = path[i] % gridSize;
            cout << "(" << x << "," << y << ")";
            if (i < path.size() - 1) {
                cout << " -> ";
            }
        }
        cout << endl;

        cout << "Total travel time: " << grid.getTotalTravelTime(path) << endl;

        cout << "Grid representation:" << endl;
        grid.printGridWithPath(path);
    }

    return 0;
}
