    private static final int INITIAL_CAPACITY = 1000;

    public FileMetadataCache() {
        fileCache = new ArrayList<>(INITIAL_CAPACITY);
    }

    public void addFile(String filename, long lastModified, long fileSize) {
        FileMetadata metadata = new FileMetadata(filename, lastModified, fileSize);
        fileCache.add(metadata);
    }

    public FileMetadata getFileMetadata(String filename) {
        for (FileMetadata metadata : fileCache) {
            if (metadata.getFilename().equals(filename)) {
                return metadata;
            }
        }
        return null;
    }

    public boolean removeFile(String filename) {
        Iterator<FileMetadata> iterator = fileCache.iterator();
        while (iterator.hasNext()) {
            FileMetadata metadata = iterator.next();
            if (metadata.getFilename().equals(filename)) {
                iterator.remove();
                return true;
            }
        }
        return false;
    }

    public int getCacheSize() {
        return fileCache.size();
    }

