// Buffer represents a circular buffer for temperature readings
type Buffer struct {
	data        []float64
	size        int
	capacity    int
	totalValues int
}

// NewBuffer creates a new Buffer with the specified capacity
func NewBuffer(capacity int) *Buffer {
	return &Buffer{
		data:        make([]float64, capacity),
		size:        0,
		capacity:    capacity,
		totalValues: 0,
	}
}

// Add adds a new temperature reading to the buffer
func (b *Buffer) Add(value float64) {
	if b.size < b.capacity {
		b.data[b.size] = value
		b.size++
	} else {
		// Shift all elements to the left
		copy(b.data, b.data[1:])
		b.data[b.capacity-1] = value
	}
	b.totalValues++
}

// Average calculates the moving average of the buffer
func (b *Buffer) Average() (float64, error) {
	if b.size == 0 {
		return 0, fmt.Errorf("buffer is empty")
	}

	sum := 0.0
	for i := 0; i < b.size; i++ {
		sum += b.data[i]
	}
	return sum / float64(b.size), nil
}

// Size returns the current size of the buffer
func (b *Buffer) Size() int {
	return b.size
}

// TotalValues returns the total number of values processed
func (b *Buffer) TotalValues() int {
	return b.totalValues
}

// Sensor represents a temperature sensor
type Sensor struct {
	ID     string
	buffer *Buffer
	logger *log.Logger
}

// NewSensor creates a new sensor with the specified ID and buffer capacity
func NewSensor(id string, bufferCapacity int, logger *log.Logger) *Sensor {
	return &Sensor{
		ID:     id,
		buffer: NewBuffer(bufferCapacity),
		logger: logger,
	}
}

// ProcessReading processes a temperature reading
func (s *Sensor) ProcessReading(temperature float64) {
	s.logger.Printf("INFO: Sensor %s received temperature reading: %.2f", s.ID, temperature)

	// Check for overflow
	if s.buffer.TotalValues() >= 1000 {
		s.logger.Printf("WARNING: Sensor %s has reached maximum capacity (1000 readings)", s.ID)
	}

	s.buffer.Add(temperature)

	avg, err := s.buffer.Average()
	if err != nil {
		s.logger.Printf("ERROR: Failed to calculate average for sensor %s: %v", s.ID, err)
		return
	}

	s.logger.Printf("INFO: Sensor %s current moving average: %.2f (from %d readings)", 
		s.ID, avg, s.buffer.Size())
}

func main() {
	// Configure loggers
	infoLogger := log.New(os.Stdout, "TEMPERATURE_PROCESSOR: ", log.Ldate|log.Ltime)

	// Create sensors
	sensors := map[string]*Sensor{
		"sensor1": NewSensor("sensor1", 10, infoLogger),
		"sensor2": NewSensor("sensor2", 10, infoLogger),
		"sensor3": NewSensor("sensor3", 10, infoLogger),
