// Structure to represent an electronic item
struct Item {
    int id;
    std::string name;
    int urgency;  // Higher value means higher priority
    double price;

    // Operator overloading for priority queue comparison
    bool operator<(const Item& other) const {
        return urgency < other.urgency;  // Higher urgency has higher priority
    }
};

class InventorySystem {
private:
    std::priority_queue<Item> items;
    const int MAX_CAPACITY = 500;
    int nextId = 1;

public:
    // Add an item to the inventory
    void addItem(const std::string& name, int urgency, double price) {
        if (items.size() >= MAX_CAPACITY) {
            throw std::overflow_error("Inventory is full (max 500 items). Remove items before adding more.");
        }

        Item newItem{nextId++, name, urgency, price};
        items.push(newItem);
        std::cout << "Added item: " << name << " (ID: " << newItem.id << ", Urgency: " << urgency << ")\n";
    }

    // Remove the highest priority item
    Item removeHighestPriority() {
        if (items.empty()) {
            throw std::underflow_error("Inventory is empty. No items to remove.");
        }

        Item topItem = items.top();
        items.pop();
        std::cout << "Removed highest priority item: " << topItem.name << " (ID: " << topItem.id << ")\n";
        return topItem;
    }

    // Get the highest priority item without removing it
    Item getHighestPriority() const {
        if (items.empty()) {
            throw std::underflow_error("Inventory is empty. No items available.");
        }

        return items.top();
    }

    // Get the current size of the inventory
    int size() const {
        return items.size();
    }

    // Check if the inventory is empty
    bool isEmpty() const {
        return items.empty();
    }

    // Check if the inventory is full
    bool isFull() const {
        return items.size() >= MAX_CAPACITY;
    }
};

int main() {
    InventorySystem inventory;

    try {
        // Add some items
        inventory.addItem("Smartphone", 10, 599.99);
        inventory.addItem("Laptop", 8, 1299.99);
        inventory.addItem("USB Cable", 3, 9.99);
        inventory.addItem("Headphones", 6, 149.99);
        inventory.addItem("Power Bank", 7, 49.99);

        // Display current inventory size
        std::cout << "Current inventory size: " << inventory.size() << "\n";

        // Get highest priority item without removing
        Item highestPriority = inventory.getHighestPriority();
        std::cout << "Highest priority item: " << highestPriority.name 
                  << " (ID: " << highestPriority.id 
                  << ", Urgency: " << highestPriority.urgency << ")\n";

        // Remove highest priority items
        Item removed1 = inventory.removeHighestPriority();
        Item removed2 = inventory.removeHighestPriority();

        // Check updated inventory size
        std::cout << "Updated inventory size: " << inventory.size() << "\n";

        // Add more items
        inventory.addItem("Smart TV", 9, 899.99);
        inventory.addItem("Wireless Charger", 4, 29.99);

        // Get highest priority again
        highestPriority = inventory.getHighestPriority();
        std::cout << "New highest priority item: " << highestPriority.name << "\n";

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
    }

    return 0;
