func FilterByDepartment(employees []Employee, departmentToFilter string) ([]Employee, error) {
	if employees == nil {
		return nil, errors.New("employee list cannot be nil")
	}

	if len(employees) > 5000 {
		return nil, errors.New("employee list exceeds maximum supported size of 5000")
	}

	result := make([]Employee, 0, len(employees))

	for _, emp := range employees {
		if emp.Department != departmentToFilter {
			result = append(result, emp)
		}
	}

