use smallvec::{smallvec, SmallVec};
use std::cmp::Ordering;
use std::error::Error;
use std::fmt;

// Define the Task struct
#[derive(Debug, Clone, PartialEq, Eq)]
struct Task {
    id: u64,
    priority: u32,
    description: String,
}

impl Ord for Task {
    fn cmp(&self, other: &Self) -> Ordering {
        // Higher priority values come first
        other.priority.cmp(&self.priority)
    }
}

impl PartialOrd for Task {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Define the custom error type
#[derive(Debug)]
enum TaskQueueError {
    QueueFull,
    TaskNotFound,
}

impl fmt::Display for TaskQueueError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            TaskQueueError::QueueFull => write!(f, "Task queue is full"),
            TaskQueueError::TaskNotFound => write!(f, "Task not found in queue"),
        }
    }
}

impl Error for TaskQueueError {}

// Define the PriorityQueue struct
struct PriorityQueue {
    tasks: SmallVec<[Task; 200]>,
    capacity: usize,
}

impl PriorityQueue {
    // Create a new priority queue
    fn new() -> Self {
        Self {
            tasks: smallvec![],
            capacity: 200,
        }
    }

    // Add a task to the queue
    fn add_task(&mut self, task: Task) -> Result<(), TaskQueueError> {
        if self.tasks.len() >= self.capacity {
            return Err(TaskQueueError::QueueFull);
        }

        self.tasks.push(task);
        self.tasks.sort_unstable();
        Ok(())
    }

    // Update a task's priority
    fn update_priority(&mut self, id: u64, new_priority: u32) -> Result<(), TaskQueueError> {
        for task in &mut self.tasks {
            if task.id == id {
                task.priority = new_priority;
                self.tasks.sort_unstable();
                return Ok(());
            }
        }
        Err(TaskQueueError::TaskNotFound)
    }

    // Remove a task by id
    fn remove_task(&mut self, id: u64) -> Result<Task, TaskQueueError> {
        let pos = self.tasks.iter().position(|task| task.id == id);
        match pos {
            Some(index) => Ok(self.tasks.remove(index)),
            None => Err(TaskQueueError::TaskNotFound),
        }
    }

    // Get next task without removing it
    fn peek(&self) -> Option<&Task> {
        self.tasks.first()
    }

    // Remove and return the highest priority task
    fn pop(&mut self) -> Option<Task> {
        if self.tasks.is_empty() {
            None
        } else {
            Some(self.tasks.remove(0))
        }
    }

    // Set a new capacity (if we need to adjust at runtime)
    fn set_capacity(&mut self, new_capacity: usize) {
        self.capacity = new_capacity;
    }

    // Get current number of tasks
    fn len(&self) -> usize {
        self.tasks.len()
    }

    // Check if queue is empty
    fn is_empty(&self) -> bool {
        self.tasks.is_empty()
    }
}
