 ```go
package main

import (
	"bufio"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"sync"
)

type LogProcessor struct {
	entryCounts     map[string]int
	mutex           sync.RWMutex
	maxEntries      int
	processedCount  int
	discardedCount  int
}

func NewLogProcessor(maxEntries int) *LogProcessor {
	return &LogProcessor{
		entryCounts: make(map[string]int),
		maxEntries:  maxEntries,
	}
}

func (lp *LogProcessor) processLine(line string) {
	line = strings.TrimSpace(line)
	if line == "" {
		return
	}

	lp.mutex.Lock()
	defer lp.mutex.Unlock()

	lp.processedCount++

	if _, exists := lp.entryCounts[line]; exists {
		lp.entryCounts[line]++
		return
	}

	if len(lp.entryCounts) < lp.maxEntries {
		lp.entryCounts[line] = 1
	} else {
		lp.discardedCount++
	}
}

func (lp *LogProcessor) processFile(filePath string, wg *sync.WaitGroup) {
	defer wg.Done()

	file, err := os.Open(filePath)
	if err != nil {
		fmt.Printf("Error opening file %s: %v\n", filePath, err)
		return
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 0, 64*1024), 1024*1024) // Increase buffer size for large lines

	for scanner.Scan() {
		lp.processLine(scanner.Text())
	}

	if err := scanner.Err(); err != nil {
		fmt.Printf("Error reading file %s: %v\n", filePath, err)
	}
}

func (lp *LogProcessor) getResults() (map[string]int, int, int) {
	lp.mutex.RLock()
	defer lp.mutex.RUnlock()

	// Create a copy of the map to avoid concurrent modification
	result := make(map[string]int, len(lp.entryCounts))
	for k, v := range lp.entryCounts {
		result[k] = v
	}

	return result, lp.processedCount, lp.discardedCount
}

func main() {
	if len(os.Args) < 2 {
		fmt.Println("Usage: ./logprocessor <directory or file paths...>")
		os.Exit(1)
	}

	processor := NewLogProcessor(20000)
	var wg sync.WaitGroup

	for _, arg := range os.Args[1:] {
		fileInfo, err := os.Stat(arg)
		if err != nil {
			fmt.Printf("Error accessing %s: %v\n", arg, err)
			continue
		}

		if fileInfo.IsDir() {
			// Process all files in directory
			err := filepath.Walk(arg, func(path string, info os.FileInfo, err error) error {
				if err != nil {
					return err
				}

				if !info.IsDir() {
					wg.Add(1)
					go processor.processFile(path, &wg)
				}
				return nil
			})

			if err != nil {
				fmt.Printf("Error walking directory %s: %v\n", arg, err)
			}
		} else {
			// Process single file
			wg.Add(1)
			go processor.processFile(arg, &wg)
		}
	}

	wg.Wait()

	results, processed, discarded := processor.getResults()

	fmt.Printf("Processed %d log entries\n", processed)
	fmt.Printf("Unique entries tracked: %d\n", len(results))
	fmt.Printf("Entries discarded (exceeded limit): %d\n", discarded)

	// Print top entries (optional)
