fn add_employee_data(data: &mut ArrayVec<(u32, f64), 100>, employee_id: u32, score: f64) -> Result<(), String> {
    // Check if the employee already exists
    for &(id, _) in data.iter() {
        if id == employee_id {
            let message = format!("Employee ID {} already exists, updating score to {}", employee_id, score);
            warn!("{}", message);
            return Err(message);
        }
    }

    // Try to add the data to the ArrayVec
    match data.try_push((employee_id, score)) {
        Ok(_) => {
            info!("Added data for employee ID {}: score {}", employee_id, score);
            Ok(())
        }
        Err(_) => {
            let message = "Cannot add more data, capacity limit of 100 reached".to_string();
            error!("{}", message);
            Err(message)
        }
    }
}

// Function to calculate average scores for each employee
fn calculate_average_scores(data: &ArrayVec<(u32, f64), 100>) -> Result<HashMap<u32, f64>, String> {
    if data.is_empty() {
        let message = "No data available for processing".to_string();
        warn!("{}", message);
        return Err(message);
    }

    info!("Calculating average scores for {} data points", data.len());

    // Create a HashMap to store sums and counts for each employee
    let mut sums: HashMap<u32, f64> = HashMap::new();
    let mut counts: HashMap<u32, u32> = HashMap::new();

    // Calculate sums and counts
    for &(id, score) in data.iter() {
        *sums.entry(id).or_insert(0.0) += score;
        *counts.entry(id).or_insert(0) += 1;
    }

    // Calculate averages
    let mut averages: HashMap<u32, f64> = HashMap::new();
    for (id, sum) in sums {
        let count = counts.get(&id).unwrap_or(&1);
        averages.insert(id, sum / *count as f64);
    }

    info!("Successfully calculated averages for {} employees", averages.len());
