int longestConsecutive(vector<int>& nums) {
    if (nums.empty()) return 0;

    // Use unordered_set as a hash map to store elements
    unordered_set<int> numSet;

    // Add elements to the set while ensuring size constraint
    for (int num : nums) {
        if (numSet.size() < 1000) {
            numSet.insert(num);
        } else {
            break;  // Stop adding if we reach size constraint
        }
    }

    int longestStreak = 0;

    for (int num : numSet) {
        // Only start counting sequences at the beginning of a sequence
        if (numSet.find(num - 1) == numSet.end()) {
            int currentNum = num;
            int currentStreak = 1;

            // Count consecutive elements
            while (numSet.find(currentNum + 1) != numSet.end()) {
                currentNum++;
                currentStreak++;
            }

            longestStreak = max(longestStreak, currentStreak);
        }
    }

    return longestStreak;
}
