// Definition for singly-linked list node
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

bool hasCycle(ListNode *head) {
    std::unordered_set<ListNode*> visited;

    while (head != nullptr) {
        // If this node is already in our set, we've found a cycle
        if (visited.find(head) != visited.end()) {
            return true;
        }

        // Add current node to set
        visited.insert(head);

        // Move to the next node
        head = head->next;
    }

    // If we reach the end of the list, there's no cycle
    return false;
}

// Test function
int main() {
    // Create a linked list with a cycle
    ListNode* head = new ListNode(1);
    ListNode* node2 = new ListNode(2);
    ListNode* node3 = new ListNode(3);
    ListNode* node4 = new ListNode(4);

    head->next = node2;
    node2->next = node3;
    node3->next = node4;
    node4->next = node2; // Creates a cycle

    if (hasCycle(head)) {
        std::cout << "Linked list has a cycle" << std::endl;
    } else {
        std::cout << "Linked list does not have a cycle" << std::endl;
    }

    return 0;
}
