package main

import (
	"fmt"
	"strconv"
	"strings"
)

// Book represents a book in the library
type Book struct {
	Title        string
	Author       string
	Year         int
	IsIssued     bool
	ISBN         string // Using ISBN as a unique identifier
}

// Library represents the virtual library system
type Library struct {
	Books       []Book
	BooksByISBN map[string]int // Maps ISBN to index in Books slice for O(1) lookup
}

// NewLibrary creates a new library instance
func NewLibrary() *Library {
	return &Library{
		Books:       make([]Book, 0, 800), // Pre-allocate capacity for 800 books
		BooksByISBN: make(map[string]int),
	}
}

// AddBook adds a new book to the library
func (l *Library) AddBook(title, author string, year int, isbn string) bool {
	// Check if book already exists
	if _, exists := l.BooksByISBN[isbn]; exists {
		return false
	}

	// Create new book
	book := Book{
		Title:    title,
		Author:   author,
		Year:     year,
		IsIssued: false,
		ISBN:     isbn,
	}

	// Add to library
	l.Books = append(l.Books, book)
	l.BooksByISBN[isbn] = len(l.Books) - 1
	return true
}

// RemoveBook removes a book from the library by ISBN
func (l *Library) RemoveBook(isbn string) bool {
	idx, exists := l.BooksByISBN[isbn]
	if !exists {
		return false
	}

	// Remove book from slice
	lastIdx := len(l.Books) - 1
	if idx < lastIdx {
		l.Books[idx] = l.Books[lastIdx]
		// Update index for the moved book
		l.BooksByISBN[l.Books[idx].ISBN] = idx
	}
	l.Books = l.Books[:lastIdx]

	// Remove from map
	delete(l.BooksByISBN, isbn)
	return true
}

// FindBookByISBN finds a book by its ISBN
func (l *Library) FindBookByISBN(isbn string) (Book, bool) {
	idx, exists := l.BooksByISBN[isbn]
	if !exists {
		return Book{}, false
	}
	return l.Books[idx], true
}

// FindBooksByAuthor finds all books by a given author
func (l *Library) FindBooksByAuthor(author string) []Book {
	var results []Book

	for _, book := range l.Books {
		if strings.Contains(strings.ToLower(book.Author), strings.ToLower(author)) {
			results = append(results, book)
		}
	}

	return results
}

// FindBooksByTitle finds all books with a title containing the search term
func (l *Library) FindBooksByTitle(title string) []Book {
	var results []Book

	for _, book := range l.Books {
		if strings.Contains(strings.ToLower(book.Title), strings.ToLower(title)) {
			results = append(results, book)
		}
	}

	return results
}

// IssueBook marks a book as issued
func (l *Library) IssueBook(isbn string) bool {
	idx, exists := l.BooksByISBN[isbn]
	if !exists || l.Books[idx].IsIssued {
		return false
	}

	l.Books[idx].IsIssued = true
	return true
}

// ReturnBook marks a book as returned
func (l *Library) ReturnBook(isbn string) bool {
	idx, exists := l.BooksByISBN[isbn]
	if !exists || !l.Books[idx].IsIssued {
		return false
	}

	l.Books[idx].IsIssued = false
	return true
}

// GetAllBooks returns all books in the library
func (l *Library) GetAllBooks() []Book {
	return l.Books
}

// GetAvailableBooks returns all books that are not issued
func (l *Library) GetAvailableBooks() []Book {
	var available []Book

	for _, book := range l.Books {
		if !book.IsIssued {
			available = append(available, book)
		}
	}

	return available
}

func main() {
	// Initialize the library
	library := NewLibrary()

	// Add some sample books
	library.AddBook("The Go Programming Language", "Alan A. A. Donovan, Brian W. Kernighan", 2015, "978-0134190440")
	library.AddBook("Clean Code", "Robert C. Martin", 2008, "978-0132350884")
	library.AddBook("Design Patterns", "Erich Gamma et al", 1994, "978-0201633610")

	// Issue a book
	library.IssueBook("978-0134190440")

	// Display all books
	fmt.Println("All books in library:")
	for _, book := range library.GetAllBooks() {
		status := "Available"
		if book.IsIssued {
			status = "Issued"
		}
		fmt.Printf("Title: %s, Author: %s, Year: %d, Status: %s\n", 
			book.Title, book.Author, book.Year, status)
	}

	// Find books by author
	martinBooks := library.FindBooksByAuthor("Martin")
	fmt.Println("\nBooks by Martin:")
	for _, book := range martinBooks {
		fmt.Printf("Title: %s, Year: %d\n", book.Title, book.Year)
	}

	// Return a book
	library.ReturnBook("978-0134190440")

	// Remove a book
	library.RemoveBook("978-0201633610")

	// Display available books
	fmt.Println("\nAvailable books:")
	for _, book := range library.GetAvailableBooks() {
		fmt.Printf("Title: %s, Author: %s, Year: %d\n", 
			book.Title, book.Author, book.Year)
	}
}
