std::vector<std::vector<int>> findUniquePermutations(std::vector<int>& nums) {
    std::vector<std::vector<int>> result;
    std::sort(nums.begin(), nums.end());

    // Use a hash set to track unique permutations
    std::unordered_set<std::string> seen;

    do {
        // Convert current permutation to string for hashing
        std::string key;
        for (int num : nums) {
            key += std::to_string(num) + ",";
        }

        // Only add if this permutation hasn't been seen before
        if (seen.find(key) == seen.end()) {
            seen.insert(key);
            result.push_back(nums);
        }

        // Check size constraint
        if (result.size() >= 1500) {
            std::cout << "Warning: Reached maximum allowed vector size (1500)." << std::endl;
            break;
        }
    } while (std::next_permutation(nums.begin(), nums.end()));

    return result;
}

int main() {
    // Example usage
    std::vector<int> numbers;
    int n, num;

    std::cout << "Enter the number of elements: ";
    std::cin >> n;

    std::cout << "Enter the elements: ";
    for (int i = 0; i < n; i++) {
        std::cin >> num;
        numbers.push_back(num);
    }

    std::vector<std::vector<int>> permutations = findUniquePermutations(numbers);

    std::cout << "Unique permutations: " << std::endl;
    for (const auto& perm : permutations) {
        for (int num : perm) {
            std::cout << num << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
